// ── PILL BADGE ──
export function Pill({ label, type = 'seller', extra }) {
  const classes = {
    seller:  'pill-seller',
    buyer:   'pill-buyer',
    both:    'pill-both',
    rental:  'pill-rental',
    flat:    'pill-flat',
  };
  return (
    <>
      <span className={`pill ${classes[type] || 'pill-seller'}`}>{label}</span>
      {extra && <span className={`pill pill-flat`} style={{ marginLeft: 4 }}>{extra}</span>}
    </>
  );
}
